final class DirectCalculator {
    /** Direct multiplication; no per-iteration object creation. */
    long weightedSum(int[] numbers, int[] factors) {
        long total = 0;
        for (int factor : factors) {
            for (int n : numbers) {
                total += (long) n * factor;
            }
        }
        return total;
    }
}

