/** Internal mutable holder; reused by the caller across calls in a hot loop. */
final class MutablePoint {
    int x;
    int y;
}

final class Geometry {
    void midpoint(int ax, int ay, int bx, int by, MutablePoint out) {
        out.x = (ax + bx) >>> 1;
        out.y = (ay + by) >>> 1;
    }
}

