final class BranchlessMath {
    int abs(int x) {
        int mask = x >> 31;
        return (x + mask) ^ mask;
    }

    int max(int a, int b) {
        int diff = a - b;
        int sign = diff >> 31;
        return a - (diff & sign);
    }
}

