            Field f = Unsafe.class.getDeclaredField("theUnsafe");
            f.setAccessible(true);
            U = (Unsafe) f.get(null);
            BASE = U.arrayBaseOffset(byte[].class);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    long sum(byte[] data) {
        long s = 0;
        for (int i = 0; i < data.length; i++) s += U.getByte(data, BASE + i);
