final class UnrolledSum {
    int sum(int[] a) {
        int s0 = 0, s1 = 0, s2 = 0, s3 = 0;
        int i = 0, n = a.length - 3;
        for (; i < n; i += 4) {
            s0 += a[i];
            s1 += a[i + 1];
            s2 += a[i + 2];
            s3 += a[i + 3];
        }
        for (; i < a.length; i++) s0 += a[i];
        return s0 + s1 + s2 + s3;
    }
}

